import { BaseColorProps } from '@/type';
import { JSX } from 'solid-js';

type TimingFunction =
  | 'ease'
  | 'ease-in'
  | 'ease-out'
  | 'ease-in-out'
  | 'linear'
  | 'step-start'
  | 'step-end'
  | `steps(${number}, ${'start' | 'end'})`
  | `cubic-bezier(${number}, ${number}, ${number}, ${number})`;

type AnimationDirection = 'normal' | 'reverse' | 'alternate' | 'alternate-reverse';
type FillMode = 'none' | 'forwards' | 'backwards' | 'both';
type PlayState = 'running' | 'paused';
type TimeUnit = `${number}s` | `${number}ms`;
type IterationCount = number | 'infinite';

export interface AnimationConfig {
  name: string;
  duration?: TimeUnit;
  timingFunction?: TimingFunction;
  delay?: TimeUnit;
  iterationCount?: IterationCount;
  direction?: AnimationDirection;
  fillMode?: FillMode;
  playState?: PlayState;
}
const DEFAULT_VALUES = {
  duration: '1s',
  timingFunction: 'ease',
  delay: '0s',
  iterationCount: 1,
  direction: 'normal',
  fillMode: 'none',
  playState: 'running',
} as const;
export function renderCSSAnimation(config: AnimationConfig): string {
  const {
    name,
    duration = DEFAULT_VALUES.duration,
    timingFunction = DEFAULT_VALUES.timingFunction,
    delay = DEFAULT_VALUES.delay,
    iterationCount = DEFAULT_VALUES.iterationCount,
    direction = DEFAULT_VALUES.direction,
    fillMode = DEFAULT_VALUES.fillMode,
    playState = DEFAULT_VALUES.playState,
  } = config;

  return `${name} ${duration} ${timingFunction} ${delay} ${iterationCount} ${direction} ${fillMode} ${playState}`;
}
export function createThrottle<T extends (...args: any[]) => void>(
  fn: T,
  delay: number,
): T & { cancel: () => void } {
  let lastCall = 0;
  let timer: ReturnType<typeof setTimeout> | null = null;
  const throttled = (...args: Parameters<T>) => {
    const now = Date.now();
    const remaining = delay - (now - lastCall);
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }
    if (remaining <= 0) {
      lastCall = now;
      fn(...args);
    } else {
      timer = setTimeout(() => {
        lastCall = Date.now();
        timer = null;
        fn(...args);
      }, remaining);
    }
  };
  throttled.cancel = () => {
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }
  };
  return throttled as T & { cancel: () => void };
}
const generateRandomHexColor = (): string => {
  const randomColor = Math.floor(Math.random() * 16777215).toString(16);
  return `#${randomColor.padStart(6, '0')}`;
};

export function normalizeHexColor(value: string | undefined): string {
  if (!value) return generateRandomHexColor();
  let hex = value.trim().replace(/^#/, '');
  if (hex.length === 3) {
    hex = hex
      .split('')
      .map(char => char + char)
      .join('');
  }

  return `#${hex.toLowerCase()}`;
}
export function getColor(color?: BaseColorProps | string, defaultColor?: string) {
  switch (color) {
    case 'primary':
      return 'color-primary';
    case 'neutral':
      return 'color-neutral';
    case 'secondary':
      return 'color-secondary';
    case 'accent':
      return 'color-accent';
    case 'info':
      return 'color-info';
    case 'success':
      return 'color-success';
    case 'warning':
      return 'color-warning';
    case 'error':
      return 'color-error';
    default:
      return defaultColor ?? '';
  }
}

const lastValuesByKey = new Map<string, any>();

export function getRandomElement<T>(arr: T[], uniqueId: string): T {
  if (arr.length === 1) return arr[0];
  const lastValue = lastValuesByKey.get(uniqueId);
  let newValue: T;
  do {
    newValue = arr[Math.floor(Math.random() * arr.length)];
  } while (newValue === lastValue && arr.length > 1);

  lastValuesByKey.set(uniqueId, newValue);
  return newValue;
}
export const genSVGCubicBezier: (
  keySplines: string,
) => Pick<
  JSX.AnimateSVGAttributes<SVGAnimateElement>,
  'calcMode' | 'keyTimes' | 'keySplines'
> = keySplines => ({
  calcMode: 'spline',
  keyTimes: '0; 1',
  keySplines: keySplines,
});

export type Image = Omit<JSX.ImgHTMLAttributes<HTMLImageElement>, 'src'> & { src: string };

export function toMarkdownCode(code: string, lang = 'tsx'): string {
  return `\`\`\`${lang}\n${code}\n\`\`\``;
}
